vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2;
float ang2, c, s;
vUv -= 0.5;
vUv *= uAspect.xy;

vec2 tmp = vUv;
ret1 = 0;
int anz = 4;
int n = 0;
while (n <= anz) {
    ang2 = 6.28*n/anz;
    c = cos(ang2);
    s = sin(ang2);
    uv2.x =  vUv.x*c - vUv.y*s;
    uv2.y =  vUv.x*s + vUv.y*c;
    neu = GetPixel (uv2 + 0.4 + .02*q27 );
    blur= GetBlur1 (uv2 + 0.4 + .02*q27 );
    ret1 = max(ret1, neu+blur*2);
n++;
}


ret = (ret1-0.0125)*0.85;


  fragColor = ret;
}
